  originalContent: string;
  timestamp: number;
  candidateId: string;
}

// ============================================================
// Evaluation Result (LLM-as-Judge)
// ============================================================

export interface LLMEvaluationResult {
  score: number;           // 0-1 overall score
  clarity: number;         // 1-10
  completeness: number;    // 1-10
  actionability: number;   // 1-10
