    {
      "priority": 4,
      "description": "Stop setInterval background tasks (heartbeat + proactive check) on plugin deregister to prevent resource leaks when plugin is unloaded."
    },
    {
      "priority": 5,
      "description": "Remove dead stubs: zcrystal_layers_exchange, zcrystal_predict, zcrystal_hook_register, zcrystal_hook_list, zcrystal_coordinator_queue — these always return placeholder/failure responses."
